example.code:
{
  "__faion_header__": {
    "methodology": "voice-ui",
    "version": "1.1.0",
    "produces": "spec"
  },
  "platform": "custom-llm",
  "intents": [
    {
      "name": "schedule-appointment",
      "sample_utterances": [
        "book a meeting Tuesday at 3",
        "schedule for tomorrow morning",
        "set up an appointment"
      ],
      "slots": [
        {
          "name": "datetime",
          "type": "datetime"
        }
      ],
      "prompt": "When should I schedule it?",
      "error_ladder": [
        "I didn't catch the time. Try again?",
        "You can say something like 'Tuesday at 3 PM'.",
        "Let me hand off to a human."
      ],
      "irreversible": false
    },
    {
      "name": "send-payment",
      "sample_utterances": [
        "send $50 to Alice",
        "pay Bob fifty bucks",
        "transfer $100 to mom"
      ],
      "slots": [
        {
          "name": "amount",
          "type": "currency"
        },
        {
          "name": "recipient",
          "type": "contact"
        }
      ],
      "prompt": "Send $50 to Alice. Confirm?",
      "error_ladder": [
        "Say yes to confirm, or cancel.",
        "You can say 'yes' or 'cancel'.",
        "Cancelling. Try again from the start."
      ],
      "irreversible": true,
      "confirmation_prompt": "Yes / Cancel"
    }
  ],
  "barge_in": true
}

{
  "platform": "custom-llm",
  "intents": [
    {
      "name": "pay",
      "sample_utterances": [
        "pay"
      ],
      "prompt": "I will now proceed to process your payment immediately",
      "error_ladder": [
        "didn't catch"
      ]
    }
  ],
  "barge_in": false
}
